import express, { Request, Response, NextFunction } from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import dotenv from 'dotenv';
import type { ServerConfig, AppConfig, HealthCheckResponse, GlobalError } from '../types';
import authRoutes from './routes/authRoutes';
import userRoutes from './routes/userRoutes';
import productRoutes from './routes/productRoutes';

// 加载环境变量
dotenv.config();

// ============================================================
// 服务端配置
// ============================================================

const serverConfig: ServerConfig = {
  port: parseInt(process.env.PORT || '3000', 10),
  mongoUri: process.env.MONGO_URI || 'mongodb://localhost:27017/auth-system',
  jwtSecret: process.env.JWT_SECRET || 'your-jwt-secret-key',
  jwtRefreshSecret: process.env.JWT_REFRESH_SECRET || 'your-jwt-refresh-secret-key',
  jwtExpiresIn: process.env.JWT_EXPIRES_IN || '15m',
  jwtRefreshExpiresIn: process.env.JWT_REFRESH_EXPIRES_IN || '7d',
  corsOrigins: process.env.CORS_ORIGINS?.split(',') || ['http://localhost:3000', 'http://localhost:5173'],
  logLevel: (process.env.LOG_LEVEL as ServerConfig['logLevel']) || 'info',
};

// 应用配置
const appConfig: AppConfig = {
  server: serverConfig,
  environment: (process.env.NODE_ENV as AppConfig['environment']) || 'development',
  isDev: process.env.NODE_ENV !== 'production',
  isProd: process.env.NODE_ENV === 'production',
};

// ============================================================
// Express 应用创建
// ============================================================

const app = express();

// ============================================================
// 全局中间件
// ============================================================

// 安全头
app.use(helmet());

// CORS 配置
app.use(cors({
  origin: (origin, callback) => {
    // 允许没有 origin 的请求（如 Postman、curl）
    if (!origin || appConfig.server.corsOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`CORS: Origin ${origin} not allowed`));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Requested-With'],
}));

// JSON 解析
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// 请求日志
app.use(morgan(appConfig.server.logLevel, {
  skip: (req) => req.url === '/api/v1/health',
}));

// 请求ID中间件
app.use((req: Request, _res: Response, next: NextFunction) => {
  (req as Request & { requestId: string }).requestId = 
    `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  next();
});

// ============================================================
// 路由挂载
// ============================================================

// 健康检查端点
app.get('/api/v1/health', (_req: Request, res: Response) => {
  const mongoStatus = mongoose.connection.readyState;
  const databaseStatus: HealthCheckResponse['database'] = 
    mongoStatus === 1 ? 'connected' : 
    mongoStatus === 2 ? 'connected' : 
    'disconnected';

  const healthResponse: HealthCheckResponse = {
    status: 'ok',
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    database: databaseStatus,
    version: process.env.APP_VERSION || '1.0.0',
  };

  res.status(200).json(healthResponse);
});

// API 路由
app.use('/api/v1/auth', authRoutes);
app.use('/api/v1/users', userRoutes);
app.use('/api/v1/products', productRoutes);

// ============================================================
// 全局错误处理中间件
// ============================================================

// 404 处理
app.use((_req: Request, res: Response) => {
  const error: GlobalError = {
    message: 'Resource not found',
    statusCode: 404,
    code: 'NOT_FOUND',
    isOperational: true,
  };
  res.status(404).json(error);
});

// 全局错误处理
app.use((err: GlobalError | Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('[Error]', err);

  const globalError: GlobalError = {
    message: err.message || 'Internal server error',
    statusCode: (err as GlobalError).statusCode || 500,
    code: (err as GlobalError).code || 'INTERNAL_ERROR',
    stack: appConfig.isDev ? err.stack : undefined,
    isOperational: (err as GlobalError).isOperational ?? false,
  };

  // 生产环境中不暴露错误详情
  if (appConfig.isProd && globalError.statusCode === 500) {
    globalError.message = 'Internal server error';
    globalError.stack = undefined;
  }

  res.status(globalError.statusCode).json({
    success: false,
    error: globalError,
  });
});

// ============================================================
// 数据库连接
// ============================================================

const connectDatabase = async (): Promise<void> => {
  try {
    const options = {
      maxPoolSize: 10,
      serverSelectionTimeoutMS: 5000,
      socketTimeoutMS: 45000,
    };

    await mongoose.connect(appConfig.server.mongoUri, options);
    console.log('[MongoDB] Connected successfully to:', appConfig.server.mongoUri);

    // 监听连接事件
    mongoose.connection.on('error', (err) => {
      console.error('[MongoDB] Connection error:', err);
    });

    mongoose.connection.on('disconnected', () => {
      console.warn('[MongoDB] Disconnected');
    });

    mongoose.connection.on('reconnected', () => {
      console.log('[MongoDB] Reconnected');
    });

  } catch (error) {
    console.error('[MongoDB] Failed to connect:', error);
    process.exit(1);
  }
};

// ============================================================
// 服务器启动
// ============================================================

const startServer = async (): Promise<void> => {
  try {
    // 连接数据库
    await connectDatabase();

    // 启动服务器
    const server = app.listen(appConfig.server.port, () => {
      console.log('========================================');
      console.log(`[Server] Starting ${appConfig.environment} server...`);
      console.log(`[Server] Listening on port: ${appConfig.server.port}`);
      console.log(`[Server] Health check: http://localhost:${appConfig.server.port}/api/v1/health`);
      console.log('========================================');
      console.log('[Routes] Auth:    POST /api/v1/auth/register');
      console.log('[Routes] Auth:    POST /api/v1/auth/login');
      console.log('[Routes] Auth:    POST /api/v1/auth/logout');
      console.log('[Routes] Users:   GET /api/v1/users/me');
      console.log('[Routes] Users:   GET /api/v1/users/:id');
      console.log('[Routes] Users:   PUT /api/v1/users/me');
      console.log('[Routes] Products: GET /api/v1/products');
      console.log('[Routes] Products: GET /api/v1/products/:id');
      console.log('[Routes] Products: POST /api/v1/products');
      console.log('[Routes] Products: PUT /api/v1/products/:id');
      console.log('[Routes] Products: DELETE /api/v1/products/:id');
      console.log('========================================');
    });

    // 优雅关闭
    const gracefulShutdown = async (signal: string): Promise<void> => {
      console.log(`\n[Server] Received ${signal}. Shutting down gracefully...`);

      server.close(async () => {
        console.log('[Server] HTTP server closed');

        try {
          await mongoose.connection.close();
          console.log('[MongoDB] Connection closed');
        } catch (err) {
          console.error('[MongoDB] Error closing connection:', err);
        }

        process.exit(0);
      });

      // 强制关闭超时
      setTimeout(() => {
        console.error('[Server] Forced shutdown after timeout');
        process.exit(1);
      }, 10000);
    };

    process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
    process.on('SIGINT', () => gracefulShutdown('SIGINT'));

    // 未捕获异常处理
    process.on('uncaughtException', (err) => {
      console.error('[Server] Uncaught Exception:', err);
      gracefulShutdown('uncaughtException');
    });

    process.on('unhandledRejection', (reason, promise) => {
      console.error('[Server] Unhandled Rejection at:', promise, 'reason:', reason);
    });

  } catch (error) {
    console.error('[Server] Failed to start:', error);
    process.exit(1);
  }
};

// 启动服务器
startServer();

// 导出配置供其他模块使用
export { app, appConfig, serverConfig };

import mongoose, { Schema, Model, Document, ConnectOptions } from 'mongoose';
import bcrypt from 'bcryptjs';
import type {
  DbUser,
  DbProduct,
  CreateUserParams,
  UpdateUserParams,
  CreateProductParams,
  UpdateProductParams,
  DatabaseConfig,
  DatabaseConnection,
  SafeUser,
  UserRole,
} from '../types';

// ============================================================
// User Role Enum
// ============================================================

export enum UserRole {
  ADMIN = 'admin',
  USER = 'user',
  GUEST = 'guest',
}

// ============================================================
// User Schema & Model
// ============================================================

const userSchema = new Schema<DbUser>(
  {
    email: {
      type: String,
      required: true,
      unique: true,
      lowercase: true,
      trim: true,
    },
    password: {
      type: String,
      required: true,
      select: false,
    },
    name: {
      type: String,
      required: true,
      trim: true,
    },
    avatar: {
      type: String,
      default: null,
    },
    role: {
      type: String,
      enum: Object.values(UserRole),
      default: UserRole.USER,
    },
    isActive: {
      type: Boolean,
      default: true,
    },
    refreshToken: {
      type: String,
      default: null,
      select: false,
    },
    lastLoginAt: {
      type: Date,
      default: null,
    },
  },
  {
    timestamps: true,
    toJSON: {
      virtuals: true,
      transform: (_doc, ret) => {
        delete ret.password;
        delete ret.refreshToken;
        delete ret.__v;
        return ret;
      },
    },
    toObject: {
      virtuals: true,
    },
  }
);

// Indexes
userSchema.index({ email: 1 }, { unique: true });
userSchema.index({ role: 1 });
userSchema.index({ createdAt: -1 });

// Virtual field: profile
userSchema.virtual('profile').get(function () {
  return `${this.name} (${this.email})`;
});

// Instance method: comparePassword
userSchema.methods.comparePassword = async function (
  candidatePassword: string
): Promise<boolean> {
  return bcrypt.compare(candidatePassword, this.password);
};

// Static method: hashPassword
userSchema.statics.hashPassword = async (
  password: string
): Promise<string> => {
  const salt = await bcrypt.genSalt(12);
  return bcrypt.hash(password, salt);
};

// Static method: createUser
userSchema.statics.createUser = async function (
  params: CreateUserParams
): Promise<SafeUser> {
  const hashedPassword = await this.hashPassword(params.password);

  const user = new this({
    email: params.email,
    password: hashedPassword,
    name: params.name,
    avatar: params.avatar,
    role: params.role || UserRole.USER,
  });

  await user.save();
  return user.toJSON() as SafeUser;
};

// Static method: findByEmail
userSchema.statics.findByEmail = function (
  email: string,
  includePassword: boolean = false
): Promise<DbUser | null> {
  const query = this.findOne({ email: email.toLowerCase() });
  if (includePassword) {
    return query.select('+password');
  }
  return query;
};

// Static method: updateUser
userSchema.statics.updateUser = async function (
  userId: string,
  params: UpdateUserParams
): Promise<SafeUser | null> {
  const user = await this.findByIdAndUpdate(
    userId,
    { $set: params },
    { new: true, runValidators: true }
  );
  return user ? (user.toJSON() as SafeUser) : null;
};

// Static method: verifyUserCredentials
userSchema.statics.verifyUserCredentials = async function (
  email: string,
  password: string
): Promise<SafeUser | null> {
  const user = await this.findByEmail(email, true);
  if (!user) {
    return null;
  }

  const isValid = await user.comparePassword(password);
  if (!isValid) {
    return null;
  }

  // Update last login
  user.lastLoginAt = new Date();
  await user.save();

  return user.toJSON() as SafeUser;
};

export interface IUserModel extends Model<DbUser> {
  hashPassword(password: string): Promise<string>;
  createUser(params: CreateUserParams): Promise<SafeUser>;
  findByEmail(email: string, includePassword?: boolean): Promise<DbUser | null>;
  updateUser(userId: string, params: UpdateUserParams): Promise<SafeUser | null>;
  verifyUserCredentials(email: string, password: string): Promise<SafeUser | null>;
}

export const User = mongoose.model<DbUser, IUserModel>('User', userSchema);

// ============================================================
// Product Schema & Model
// ============================================================

const productSchema = new Schema<DbProduct>(
  {
    name: {
      type: String,
      required: true,
      trim: true,
    },
    description: {
      type: String,
      required: true,
      trim: true,
    },
    price: {
      type: Number,
      required: true,
      min: 0,
    },
    category: {
      type: String,
      required: true,
      trim: true,
    },
    stock: {
      type: Number,
      default: 0,
      min: 0,
    },
    images: {
      type: [String],
      default: [],
    },
    createdBy: {
      type: String,
      required: true,
      ref: 'User',
    },
    isActive: {
      type: Boolean,
      default: true,
    },
  },
  {
    timestamps: true,
    toJSON: {
      virtuals: true,
      transform: (_doc, ret) => {
        delete ret.__v;
        return ret;
      },
    },
    toObject: {
      virtuals: true,
    },
  }
);

// Indexes
productSchema.index({ category: 1 });
productSchema.index({ createdBy: 1 });
productSchema.index({ name: 'text', description: 'text' });
productSchema.index({ price: 1 });
productSchema.index({ isActive: 1 });
productSchema.index({ createdAt: -1 });

// Static method: createProduct
productSchema.statics.createProduct = async function (
  params: CreateProductParams
): Promise<DbProduct> {
  const product = new this({
    name: params.name,
    description: params.description,
    price: params.price,
    category: params.category,
    stock: params.stock || 0,
    images: params.images || [],
    createdBy: params.createdBy,
  });

  await product.save();
  return product;
};

// Static method: findByCategory
productSchema.statics.findByCategory = function (
  category: string,
  options?: { page?: number; limit?: number; activeOnly?: boolean }
): Promise<DbProduct[]> {
  const { page = 1, limit = 20, activeOnly = true } = options || {};

  const query = this.find({ 
    category,
    ...(activeOnly && { isActive: true })
  })
    .sort({ createdAt: -1 })
    .skip((page - 1) * limit)
    .limit(limit);

  return query;
};

// Static method: findByCreator
productSchema.statics.findByCreator = function (
  createdBy: string,
  options?: { page?: number; limit?: number }
): Promise<DbProduct[]> {
  const { page = 1, limit = 20 } = options || {};

  return this.find({ createdBy })
    .sort({ createdAt: -1 })
    .skip((page - 1) * limit)
    .limit(limit);
};

// Static method: searchProducts
productSchema.statics.searchProducts = function (
  searchTerm: string,
  options?: { page?: number; limit?: number; category?: string; activeOnly?: boolean }
): Promise<DbProduct[]> {
  const { page = 1, limit = 20, category, activeOnly = true } = options || {};

  const query: Record<string, unknown> = {
    $text: { $search: searchTerm },
    ...(activeOnly && { isActive: true }),
    ...(category && { category }),
  };

  return this.find(query)
    .sort({ score: { $meta: 'textScore' } })
    .skip((page - 1) * limit)
    .limit(limit);
};

// Static method: updateProduct
productSchema.statics.updateProduct = async function (
  productId: string,
  params: UpdateProductParams
): Promise<DbProduct | null> {
  return this.findByIdAndUpdate(
    productId,
    { $set: params },
    { new: true, runValidators: true }
  );
};

// Static method: updateStock
productSchema.statics.updateStock = async function (
  productId: string,
  quantity: number
): Promise<DbProduct | null> {
  return this.findByIdAndUpdate(
    productId,
    { $inc: { stock: quantity } },
    { new: true, runValidators: true }
  );
};

export interface IProductModel extends Model<DbProduct> {
  createProduct(params: CreateProductParams): Promise<DbProduct>;
  findByCategory(category: string, options?: { page?: number; limit?: number; activeOnly?: boolean }): Promise<DbProduct[]>;
  findByCreator(createdBy: string, options?: { page?: number; limit?: number }): Promise<DbProduct[]>;
  searchProducts(searchTerm: string, options?: { page?: number; limit?: number; category?: string; activeOnly?: boolean }): Promise<DbProduct[]>;
  updateProduct(productId: string, params: UpdateProductParams): Promise<DbProduct | null>;
  updateStock(productId: string, quantity: number): Promise<DbProduct | null>;
}

export const Product = mongoose.model<DbProduct, IProductModel>('Product', productSchema);

// ============================================================
// Database Connection Manager
// ============================================================

class DatabaseConnectionManager {
  private connection: typeof mongoose | null = null;
  private config: DatabaseConfig | null = null;

  /**
   * Initialize database configuration
   */
  setConfig(config: DatabaseConfig): void {
    this.config = config;
  }

  /**
   * Connect to MongoDB
   */
  async connect(config?: DatabaseConfig): Promise<DatabaseConnection> {
    if (this.connection?.connection?.readyState === 1) {
      return this.getConnectionInfo();
    }

    const dbConfig = config || this.config;
    if (!dbConfig) {
      throw new Error('Database configuration is required');
    }

    const options: ConnectOptions = {
      maxPoolSize: dbConfig.options.maxPoolSize,
      minPoolSize: dbConfig.options.minPoolSize,
      retryWrites: dbConfig.options.retryWrites,
      retryReads: dbConfig.options.retryReads,
      serverSelectionTimeoutMS: dbConfig.options.serverSelectionTimeoutMS,
      connectTimeoutMS: dbConfig.options.connectTimeoutMS,
      socketTimeoutMS: dbConfig.options.socketTimeoutMS,
    };

    try {
      this.connection = await mongoose.connect(dbConfig.uri, options);

      // Handle connection events
      mongoose.connection.on('error', (err) => {
        console.error('MongoDB connection error:', err);
      });

      mongoose.connection.on('disconnected', () => {
        console.warn('MongoDB disconnected');
      });

      mongoose.connection.on('reconnected', () => {
        console.info('MongoDB reconnected');
      });

      return this.getConnectionInfo();
    } catch (error) {
      console.error('Failed to connect to MongoDB:', error);
      throw error;
    }
  }

  /**
   * Disconnect from MongoDB
   */
  async disconnect(): Promise<void> {
    if (this.connection) {
      await mongoose.disconnect();
      this.connection = null;
      console.info('MongoDB disconnected successfully');
    }
  }

  /**
   * Get current connection info
   */
  getConnectionInfo(): DatabaseConnection {
    const conn = mongoose.connection;
    return {
      isConnected: conn.readyState === 1,
      host: conn.host || 'unknown',
      port: conn.port || 27017,
      name: conn.name || 'unknown',
      readyState: conn.readyState,
    };
  }

  /**
   * Check if database is connected
   */
  isConnected(): boolean {
    return mongoose.connection.readyState === 1;
  }

  /**
   * Execute transaction
   */
  async withTransaction<T>(
    callback: (session: mongoose.ClientSession) => Promise<T>
  ): Promise<T> {
    const session = await mongoose.startSession();
    try {
      session.startTransaction();
      const result = await callback(session);
      await session.commitTransaction();
      return result;
    } catch (error) {
      await session.abortTransaction();
      throw error;
    } finally {
      session.endSession();
    }
  }

  /**
   * Health check
   */
  async healthCheck(): Promise<boolean> {
    try {
      if (!this.isConnected()) {
        return false;
      }
      await mongoose.connection.db?.admin().ping();
      return true;
    } catch {
      return false;
    }
  }
}

// Export singleton instance
export const databaseManager = new DatabaseConnectionManager();

// ============================================================
// Export Models
// ============================================================

export { User as UserModel, Product as ProductModel };

// ============================================================
// Default Configuration
// ============================================================

export const defaultDatabaseConfig: DatabaseConfig = {
  uri: process.env.MONGODB_URI || 'mongodb://localhost:27017/auth_app',
  options: {
    maxPoolSize: 10,
    minPoolSize: 2,
    retryWrites: true,
    retryReads: true,
    serverSelectionTimeoutMS: 5000,
    connectTimeoutMS: 10000,
    socketTimeoutMS: 45000,
    heartbeatFrequencyMS: 10000,
  },
};

// ============================================================
// Utility Functions
// ============================================================

/**
 * Initialize database with default or custom config
 */
export async function initializeDatabase(config?: DatabaseConfig): Promise<DatabaseConnection> {
  const dbConfig = config || defaultDatabaseConfig;
  databaseManager.setConfig(dbConfig);
  return databaseManager.connect(dbConfig);
}

/**
 * Close database connection
 */
export async function closeDatabase(): Promise<void> {
  await databaseManager.disconnect();
}

/**
 * Check database health
 */
export async function checkDatabaseHealth(): Promise<boolean> {
  return databaseManager.healthCheck();
}

export default {
  User,
  Product,
  databaseManager,
  initializeDatabase,
  closeDatabase,
  checkDatabaseHealth,
  defaultDatabaseConfig,
};

import { Router, Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import type {
  RegisterRequest,
  LoginRequest,
  RefreshTokenRequest,
  LogoutRequest,
  AuthResponse,
  RefreshTokenResponse,
  AuthUser,
  AuthenticatedRequest,
  LoginRateLimitConfig,
  PasswordPolicy,
  PasswordValidationResult,
} from '../types';

const router = Router();

// ============================================================
// Constants & Configuration
// ============================================================

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';
const JWT_EXPIRES_IN = '15m';
const REFRESH_TOKEN_EXPIRES_IN = '7d';

const PASSWORD_POLICY: PasswordPolicy = {
  minLength: 8,
  maxLength: 128,
  requireUppercase: true,
  requireLowercase: true,
  requireNumbers: true,
  requireSpecialChars: true,
};

const LOGIN_RATE_LIMIT_CONFIG: LoginRateLimitConfig = {
  windowMs: 15 * 60 * 1000, // 15 minutes
  maxAttempts: 5,
  message: 'Too many login attempts. Please try again later.',
};

// In-memory store for demo (replace with database in production)
const usersStore = new Map<string, { id: string; email: string; name: string; password: string; role: 'user' | 'admin' }>();
const refreshTokensStore = new Map<string, { userId: string; expiresAt: Date }>();
const loginAttempts = new Map<string, { count: number; resetAt: Date }>();

// ============================================================
// Helper Functions
// ============================================================

function generateTokens(userId: string, email: string, role: string): { accessToken: string; refreshToken: string } {
  const accessToken = crypto
    .createHmac('sha256', JWT_SECRET)
    .update(JSON.stringify({ userId, email, role, exp: Date.now() + 15 * 60 * 1000 }))
    .digest('hex');

  const refreshToken = crypto.randomBytes(64).toString('hex');
  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);

  refreshTokensStore.set(refreshToken, { userId, expiresAt });

  return { accessToken, refreshToken };
}

function validatePassword(password: string): PasswordValidationResult {
  const errors: string[] = [];

  if (password.length < PASSWORD_POLICY.minLength) {
    errors.push(`Password must be at least ${PASSWORD_POLICY.minLength} characters`);
  }
  if (password.length > PASSWORD_POLICY.maxLength) {
    errors.push(`Password must not exceed ${PASSWORD_POLICY.maxLength} characters`);
  }
  if (PASSWORD_POLICY.requireUppercase && !/[A-Z]/.test(password)) {
    errors.push('Password must contain at least one uppercase letter');
  }
  if (PASSWORD_POLICY.requireLowercase && !/[a-z]/.test(password)) {
    errors.push('Password must contain at least one lowercase letter');
  }
  if (PASSWORD_POLICY.requireNumbers && !/[0-9]/.test(password)) {
    errors.push('Password must contain at least one number');
  }
  if (PASSWORD_POLICY.requireSpecialChars && !/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password)) {
    errors.push('Password must contain at least one special character');
  }

  const valid = errors.length === 0;
  let strength: 'weak' | 'medium' | 'strong' = 'weak';

  if (valid) {
    const score = [
      password.length >= 12,
      PASSWORD_POLICY.requireUppercase,
      PASSWORD_POLICY.requireLowercase,
      PASSWORD_POLICY.requireNumbers,
      PASSWORD_POLICY.requireSpecialChars,
    ].filter(Boolean).length;

    if (score >= 4 && password.length >= 12) strength = 'strong';
    else if (score >= 3) strength = 'medium';
  }

  return { valid, errors, strength };
}

function hashPassword(password: string): string {
  return crypto.createHmac('sha256', JWT_SECRET).update(password).digest('hex');
}

function checkLoginRateLimit(ip: string): { allowed: boolean; remainingAttempts: number } {
  const attempt = loginAttempts.get(ip);
  const now = new Date();

  if (!attempt || attempt.resetAt < now) {
    return { allowed: true, remainingAttempts: LOGIN_RATE_LIMIT_CONFIG.maxAttempts - 1 };
  }

  if (attempt.count >= LOGIN_RATE_LIMIT_CONFIG.maxAttempts) {
    return { allowed: false, remainingAttempts: 0 };
  }

  return {
    allowed: true,
    remainingAttempts: LOGIN_RATE_LIMIT_CONFIG.maxAttempts - attempt.count - 1,
  };
}

function recordLoginAttempt(ip: string): void {
  const attempt = loginAttempts.get(ip);
  const now = new Date();
  const resetAt = new Date(now.getTime() + LOGIN_RATE_LIMIT_CONFIG.windowMs);

  if (!attempt || attempt.resetAt < now) {
    loginAttempts.set(ip, { count: 1, resetAt });
  } else {
    attempt.count++;
    loginAttempts.set(ip, attempt);
  }
}

function clearLoginAttempts(ip: string): void {
  loginAttempts.delete(ip);
}

// Middleware to validate auth requests
function validateRequest<T>(validator: (body: unknown) => T | null) {
  return (req: Request, res: Response, next: NextFunction) => {
    const validated = validator(req.body);
    if (!validated) {
      return res.status(400).json({
        success: false,
        message: 'Invalid request body',
      });
    }
    (req as Request & { validatedBody: T }).validatedBody = validated;
    next();
  };
}

// Auth middleware
function authMiddleware(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    res.status(401).json({
      success: false,
      message: 'No token provided',
    });
    return;
  }

  const token = authHeader.split(' ')[1];

  // In production, verify JWT token properly
  try {
    const decoded = crypto.createHmac('sha256', JWT_SECRET).update(token).digest('hex');

    // For demo purposes, decode token data from the hash
    const tokenData = JSON.parse(Buffer.from(token, 'hex').slice(0, -64).toString() || '{}');

    if (Date.now() > tokenData.exp) {
      res.status(401).json({
        success: false,
        message: 'Token expired',
      });
      return;
    }

    (req as Request & AuthenticatedRequest).user = {
      userId: tokenData.userId,
      email: tokenData.email,
      role: tokenData.role,
    };

    next();
  } catch {
    res.status(401).json({
      success: false,
      message: 'Invalid token',
    });
    return;
  }
}

