/**
 * POST /api/auth/register
 * Register a new user
 */
router.post(
  '/register',
  validateRequest((body: unknown): RegisterRequest | null => {
    const b = body as Record<string, unknown>;
    if (typeof b.email !== 'string' || typeof b.password !== 'string' || typeof b.name !== 'string') {
      return null;
    }
    return {
      email: b.email.trim().toLowerCase(),
      password: b.password,
      name: b.name.trim(),
    };
  }),
  async (req: Request, res: Response) => {
    try {
      const { email, password, name } = (req as Request & { validatedBody: RegisterRequest }).validatedBody;

      // Check if user already exists
      for (const user of usersStore.values()) {
        if (user.email === email) {
          return res.status(409).json({
            success: false,
            message: 'User with this email already exists',
          });
        }
      }

      // Validate password policy
      const passwordValidation = validatePassword(password);
      if (!passwordValidation.valid) {
        return res.status(400).json({
          success: false,
          message: 'Password does not meet requirements',
          errors: passwordValidation.errors,
          strength: passwordValidation.strength,
        });
      }

      // Create user
      const userId = crypto.randomUUID();
      const hashedPassword = hashPassword(password);

      const newUser = {
        id: userId,
        email,
        name,
        password: hashedPassword,
        role: 'user' as const,
      };

      usersStore.set(userId, newUser);

      // Generate tokens
      const tokens = generateTokens(userId, email, newUser.role);

      const response: AuthResponse = {
        success: true,
        message: 'Registration successful',
        data: {
          user: {
            id: userId,
            email,
            name,
            role: newUser.role,
            createdAt: new Date().toISOString(),
          },
          tokens,
        },
      };

      res.status(201).json(response);
    } catch (error) {
      console.error('Registration error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

/**
 * POST /api/auth/login
 * Login user
 */
router.post(
  '/login',
  validateRequest((body: unknown): LoginRequest | null => {
    const b = body as Record<string, unknown>;
    if (typeof b.email !== 'string' || typeof b.password !== 'string') {
      return null;
    }
    return {
      email: b.email.trim().toLowerCase(),
      password: b.password,
    };
  }),
  async (req: Request, res: Response) => {
    try {
      const { email, password } = (req as Request & { validatedBody: LoginRequest }).validatedBody;
      const clientIp = req.ip || 'unknown';

      // Check rate limit
      const rateLimit = checkLoginRateLimit(clientIp);
      if (!rateLimit.allowed) {
        return res.status(429).json({
          success: false,
          message: LOGIN_RATE_LIMIT_CONFIG.message,
          remainingAttempts: rateLimit.remainingAttempts,
        });
      }

      // Find user
      let foundUser: { id: string; email: string; name: string; password: string; role: 'user' | 'admin' } | null = null;

      for (const user of usersStore.values()) {
        if (user.email === email) {
          foundUser = user;
          break;
        }
      }

      if (!foundUser) {
        recordLoginAttempt(clientIp);
        return res.status(401).json({
          success: false,
          message: 'Invalid email or password',
          remainingAttempts: checkLoginRateLimit(clientIp).remainingAttempts,
        });
      }

      // Verify password
      const hashedPassword = hashPassword(password);
      if (foundUser.password !== hashedPassword) {
        recordLoginAttempt(clientIp);
        return res.status(401).json({
          success: false,
          message: 'Invalid email or password',
          remainingAttempts: checkLoginRateLimit(clientIp).remainingAttempts,
        });
      }

      // Clear rate limit on successful login
      clearLoginAttempts(clientIp);

      // Generate tokens
      const tokens = generateTokens(foundUser.id, foundUser.email, foundUser.role);

      const response: AuthResponse = {
        success: true,
        message: 'Login successful',
        data: {
          user: {
            id: foundUser.id,
            email: foundUser.email,
            name: foundUser.name,
            role: foundUser.role,
            createdAt: new Date().toISOString(),
          },
          tokens,
        },
      };

      res.json(response);
    } catch (error) {
      console.error('Login error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

/**
 * POST /api/auth/refresh
 * Refresh access token
 */
router.post(
  '/refresh',
  validateRequest((body: unknown): RefreshTokenRequest | null => {
    const b = body as Record<string, unknown>;
    if (typeof b.refreshToken !== 'string') {
      return null;
    }
    return { refreshToken: b.refreshToken };
  }),
  async (req: Request, res: Response) => {
    try {
      const { refreshToken } = (req as Request & { validatedBody: RefreshTokenRequest }).validatedBody;

      const tokenData = refreshTokensStore.get(refreshToken);

      if (!tokenData) {
        return res.status(401).json({
          success: false,
          message: 'Invalid refresh token',
        });
      }

      if (tokenData.expiresAt < new Date()) {
        refreshTokensStore.delete(refreshToken);
        return res.status(401).json({
          success: false,
          message: 'Refresh token expired',
        });
      }

      // Get user data
      const user = usersStore.get(tokenData.userId);
      if (!user) {
        return res.status(401).json({
          success: false,
          message: 'User not found',
        });
      }

      // Generate new tokens
      const tokens = generateTokens(user.id, user.email, user.role);

      // Delete old refresh token
      refreshTokensStore.delete(refreshToken);

      const response: RefreshTokenResponse = {
        success: true,
        message: 'Token refreshed successfully',
        data: tokens,
      };

      res.json(response);
    } catch (error) {
      console.error('Token refresh error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

