function generateProductId(): string {
  return crypto.randomUUID();
}

function getPaginatedResponse<T>(
  items: T[],
  page: number,
  pageSize: number
): PaginatedResponse<T> {
  const total = items.length;
  const totalPages = Math.ceil(total / pageSize);
  const start = (page - 1) * pageSize;
  const paginatedItems = items.slice(start, start + pageSize);

  return {
    items: paginatedItems,
    total,
    page,
    pageSize,
    totalPages,
  };
}

function filterProducts(products: Product[], params: ProductQueryParams): Product[] {
  return products.filter((product) => {
    if (!product.isActive && params.inStock !== false) return false;

    if (params.category && product.category !== params.category) return false;

    if (params.search) {
      const searchLower = params.search.toLowerCase();
      const matchesSearch =
        product.name.toLowerCase().includes(searchLower) ||
        product.description.toLowerCase().includes(searchLower);
      if (!matchesSearch) return false;
    }

    if (params.minPrice !== undefined && product.price < params.minPrice) return false;
    if (params.maxPrice !== undefined && product.price > params.maxPrice) return false;

    if (params.inStock === true && product.stock <= 0) return false;
    if (params.inStock === false && product.stock > 0) return false;

    if (params.createdBy && product.createdBy !== params.createdBy) return false;

    return true;
  });
}

// Validation helpers
function validateCreateProduct(body: unknown): CreateProductRequest | null {
  const b = body as Record<string, unknown>;

  if (typeof b.name !== 'string' || b.name.trim().length === 0) return null;
  if (typeof b.description !== 'string') return null;
  if (typeof b.price !== 'number' || b.price < 0) return null;
  if (typeof b.category !== 'string' || b.category.trim().length === 0) return null;

  return {
    name: (b.name as string).trim(),
    description: (b.description as string).trim(),
    price: b.price as number,
    category: (b.category as string).trim().toLowerCase(),
    stock: typeof b.stock === 'number' ? Math.max(0, b.stock) : 0,
    images: Array.isArray(b.images) ? (b.images as string[]).filter((img) => typeof img === 'string') : [],
  };
}

function validateUpdateProduct(body: unknown): UpdateProductRequest | null {
  const b = body as Record<string, unknown>;
  const result: UpdateProductRequest = {};

  if (b.name !== undefined) {
    if (typeof b.name !== 'string' || b.name.trim().length === 0) return null;
    result.name = (b.name as string).trim();
  }

  if (b.description !== undefined) {
    if (typeof b.description !== 'string') return null;
    result.description = (b.description as string).trim();
  }

  if (b.price !== undefined) {
    if (typeof b.price !== 'number' || b.price < 0) return null;
    result.price = b.price as number;
  }

  if (b.category !== undefined) {
    if (typeof b.category !== 'string' || b.category.trim().length === 0) return null;
    result.category = (b.category as string).trim().toLowerCase();
  }

  if (b.stock !== undefined) {
    if (typeof b.stock !== 'number' || b.stock < 0) return null;
    result.stock = Math.max(0, b.stock as number);
  }

  if (b.images !== undefined) {
    if (!Array.isArray(b.images)) return null;
    result.images = (b.images as string[]).filter((img) => typeof img === 'string');
  }

  return result;
}

// Validation middleware factory
function validateRequest<T>(validator: (body: unknown) => T | null) {
  return (req: Request, res: Response, next: NextFunction) => {
    const validated = validator(req.body);
    if (!validated) {
      return res.status(400).json({
        success: false,
        message: 'Invalid request body',
      });
    }
    (req as Request & { validatedBody: T }).validatedBody = validated;
    next();
  };
}

