/**
 * POST /api/products
 * Create a new product (protected)
 */
router.post(
  '/',
  authMiddleware,
  validateRequest(validateCreateProduct),
  async (req: Request, res: Response) => {
    try {
      const { name, description, price, category, stock, images } = 
        (req as Request & { validatedBody: CreateProductRequest }).validatedBody;

      // Check if category exists
      if (!categoriesStore.has(category)) {
        return res.status(400).json({
          success: false,
          message: `Category '${category}' does not exist`,
        });
      }

      const productId = generateProductId();
      const now = new Date().toISOString();

      const newProduct: Product = {
        id: productId,
        name,
        description,
        price,
        category,
        stock,
        images,
        createdBy: (req as Request & { user: { userId: string } }).user.userId,
        isActive: true,
        createdAt: now,
        updatedAt: now,
      };

      productsStore.set(productId, newProduct);

      const response: ProductMutationResponse = {
        success: true,
        message: 'Product created successfully',
        data: newProduct,
      };

      res.status(201).json(response);
    } catch (error) {
      console.error('Create product error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
