);

/**
 * PUT /api/products/:id
 * Update a product (protected)
 */
router.put(
  '/:id',
  authMiddleware,
  validateRequest(validateUpdateProduct),
  async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const updates = (req as Request & { validatedBody: UpdateProductRequest }).validatedBody;
      const userId = (req as Request & { user: { userId: string } }).user.userId;

      const existingProduct = productsStore.get(id);

      if (!existingProduct) {
        return res.status(404).json({
          success: false,
          message: 'Product not found',
        });
      }

      // Check ownership or admin role
      const user = (req as Request & { user: { role: string } }).user;
      if (existingProduct.createdBy !== userId && user.role !== 'admin') {
        return res.status(403).json({
          success: false,
          message: 'You do not have permission to update this product',
        });
      }

      // Check if new category exists
      if (updates.category && !categoriesStore.has(updates.category)) {
        return res.status(400).json({
          success: false,
          message: `Category '${updates.category}' does not exist`,
        });
      }

      const updatedProduct: Product = {
        ...existingProduct,
        ...updates,
        updatedAt: new Date().toISOString(),
      };

      productsStore.set(id, updatedProduct);

      const response: ProductMutationResponse = {
        success: true,
        message: 'Product updated successfully',
        data: updatedProduct,
      };

      res.json(response);
    } catch (error) {
      console.error('Update product error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

