 * Update product stock (protected)
 */
router.patch('/:id/stock', authMiddleware, async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const { quantity } = req.body as { quantity: number };
    const userId = (req as Request & { user: { userId: string; role: string } }).user;

    if (typeof quantity !== 'number') {
      return res.status(400).json({
        success: false,
        message: 'Quantity must be a number',
      });
    }

    const existingProduct = productsStore.get(id);

    if (!existingProduct) {
      return res.status(404).json({
        success: false,
        message: 'Product not found',
      });
    }

    // Check ownership or admin role
    if (existingProduct.createdBy !== userId.userId && userId.role !== 'admin') {
      return res.status(403).json({
        success: false,
        message: 'You do not have permission to update this product',
      });
    }

    const newStock = Math.max(0, existingProduct.stock + quantity);
    existingProduct.stock = newStock;
    existingProduct.updatedAt = new Date().toISOString();
    productsStore.set(id, existingProduct);

    const response: ProductMutationResponse = {
      success: true,
      message: `Stock ${quantity >= 0 ? 'added' : 'removed'} successfully`,
      data: existingProduct,
    };

    res.json(response);
  } catch (error) {
    console.error('Update stock error:', error);
    res.status(500).json({
      success: false,
      message: 'Internal server error',
    });
  }
});

export default router;

import { Router, Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import type {
  UpdateUserRequest,
  ChangePasswordRequest,
  UserPublic,
  CurrentUserResponse,
  UserPublicResponse,
  UserUpdateResponse,
  PasswordChangeResponse,
  UserQueryParams,
} from '../types';
import { authMiddleware, validatePassword } from './auth';

const router = Router();

// ============================================================
// Types
// ============================================================

interface SafeUser {
  id: string;
  email: string;
  name: string;
  avatar?: string;
  role: string;
  createdAt: string;
  updatedAt?: string;
}

interface UserRole {
  role: string;
}

interface PaginatedResponse<T> {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

interface TokenPair {
  accessToken: string;
  refreshToken: string;
}

interface SuccessResponse {
  success: boolean;
  message?: string;
}

// ============================================================
// In-Memory Store (Replace with Database)
// ============================================================

const usersStore = new Map<string, SafeUser & { password: string }>();
const refreshTokensStore = new Map<string, { userId: string; expiresAt: Date }>();

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';

// ============================================================
// Helper Functions
// ============================================================

function hashPassword(password: string): string {
  return crypto.createHmac('sha256', JWT_SECRET).update(password).digest('hex');
}

function generateTokens(userId: string, email: string, role: string): TokenPair {
  const accessToken = crypto
    .createHmac('sha256', JWT_SECRET)
    .update(JSON.stringify({ userId, email, role, exp: Date.now() + 15 * 60 * 1000 }))
    .digest('hex');

  const refreshToken = crypto.randomBytes(64).toString('hex');
  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);

  refreshTokensStore.set(refreshToken, { userId, expiresAt });

  return { accessToken, refreshToken };
}

function getPaginatedResponse<T>(
  items: T[],
  page: number,
  pageSize: number
): PaginatedResponse<T> {
  const total = items.length;
  const totalPages = Math.ceil(total / pageSize);
  const start = (page - 1) * pageSize;
  const paginatedItems = items.slice(start, start + pageSize);

  return {
    items: paginatedItems,
    total,
    page,
    pageSize,
    totalPages,
  };
}

function filterUsers(users: SafeUser[], params: UserQueryParams): SafeUser[] {
  return users.filter((user) => {
    if (params.role && user.role !== params.role) return false;

    if (params.search) {
      const searchLower = params.search.toLowerCase();
      const matchesSearch =
        user.name.toLowerCase().includes(searchLower) ||
        user.email.toLowerCase().includes(searchLower);
      if (!matchesSearch) return false;
    }

    return true;
  });
}

// Validation helpers
function validateUpdateUser(body: unknown): UpdateUserRequest | null {
  const b = body as Record<string, unknown>;
  const result: UpdateUserRequest = {};

  if (b.name !== undefined) {
    if (typeof b.name !== 'string' || b.name.trim().length === 0) return null;
    result.name = (b.name as string).trim();
  }

  if (b.avatar !== undefined) {
    if (b.avatar !== null && typeof b.avatar !== 'string') return null;
    result.avatar = b.avatar ? (b.avatar as string).trim() : undefined;
  }

  return result;
}

function validateChangePassword(body: unknown): ChangePasswordRequest | null {
  const b = body as Record<string, unknown>;

  if (typeof b.currentPassword !== 'string' || b.currentPassword.length === 0) return null;
  if (typeof b.newPassword !== 'string' || b.newPassword.length === 0) return null;

  return {
    currentPassword: b.currentPassword as string,
    newPassword: b.newPassword as string,
  };
}

// Validation middleware factory
function validateRequest<T>(validator: (body: unknown) => T | null) {
  return (req: Request, res: Response, next: NextFunction) => {
    const validated = validator(req.body);
    if (!validated) {
      return res.status(400).json({
        success: false,
        message: 'Invalid request body',
      });
    }
    (req as Request & { validatedBody: T }).validatedBody = validated;
    next();
  };
}

