/**
 * PUT /api/users/me
 * Update current user profile (protected)
 */
router.put(
  '/me',
  authMiddleware,
  validateRequest(validateUpdateUser),
  async (req: Request, res: Response) => {
    try {
      const userId = (req as Request & { user: { userId: string } }).user.userId;
      const updates = (req as Request & { validatedBody: UpdateUserRequest }).validatedBody;

      const user = usersStore.get(userId);

      if (!user) {
        return res.status(404).json({
          success: false,
          message: 'User not found',
        });
      }

      // Apply updates
      if (updates.name) user.name = updates.name;
      if (updates.avatar !== undefined) user.avatar = updates.avatar;
      user.updatedAt = new Date().toISOString();

      usersStore.set(userId, user);

      const safeUser: SafeUser = {
        id: user.id,
        email: user.email,
        name: user.name,
        avatar: user.avatar,
        role: user.role,
        createdAt: user.createdAt,
        updatedAt: user.updatedAt,
      };

      const response: UserUpdateResponse = {
        success: true,
        message: 'Profile updated successfully',
        data: safeUser,
      };

      res.json(response);
    } catch (error) {
      console.error('Update user error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

/**
 * PUT /api/users/me/password
 * Change current user password (protected)
 */
router.put(
  '/me/password',
  authMiddleware,
  validateRequest(validateChangePassword),
  async (req: Request, res: Response) => {
    try {
      const userId = (req as Request & { user: { userId: string } }).user.userId;
      const { currentPassword, newPassword } = 
        (req as Request & { validatedBody: ChangePasswordRequest }).validatedBody;

      const user = usersStore.get(userId);

      if (!user) {
        return res.status(404).json({
          success: false,
          message: 'User not found',
        });
      }

      // Verify current password
      const hashedCurrentPassword = hashPassword(currentPassword);
      if (user.password !== hashedCurrentPassword) {
        return res.status(401).json({
          success: false,
          message: 'Current password is incorrect',
        });
      }

      // Validate new password
      const passwordValidation = validatePassword(newPassword);
      if (!passwordValidation.valid) {
        return res.status(400).json({
          success: false,
          message: 'New password does not meet requirements',
          errors: passwordValidation.errors,
          strength: passwordValidation.strength,
        });
      }

      // Check if new password is different from current
      const hashedNewPassword = hashPassword(newPassword);
      if (hashedCurrentPassword === hashedNewPassword) {
        return res.status(400).json({
          success: false,
          message: 'New password must be different from current password',
        });
      }

      // Update password
      user.password = hashedNewPassword;
      user.updatedAt = new Date().toISOString();
      usersStore.set(userId, user);

      // Generate new tokens
      const tokens = generateTokens(user.id, user.email, user.role);

      const response: PasswordChangeResponse = {
        success: true,
        message: 'Password changed successfully',
        data: {
          tokenRefreshed: true,
          newTokens: tokens,
        },
      };

      res.json(response);
    } catch (error) {
      console.error('Change password error:', error);
      res.status(500).json({
        success: false,
        message: 'Internal server error',
      });
    }
  }
);

