/**
 * DELETE /api/users/me
 * Delete current user account (protected)
 */
router.delete('/me', authMiddleware, async (req: Request, res: Response) => {
  try {
    const userId = (req as Request & { user: { userId: string } }).user.userId;

    const user = usersStore.get(userId);

    if (!user) {
      return res.status(404).json({
        success: false,
        message: 'User not found',
      });
    }

    // Remove user from store
    usersStore.delete(userId);

    // Remove all refresh tokens for this user
    for (const [token, data] of refreshTokensStore.entries()) {
      if (data.userId === userId) {
        refreshTokensStore.delete(token);
      }
    }

    res.json({
      success: true,
      message: 'Account deleted successfully',
    });
  } catch (error) {
    console.error('Delete user error:', error);
    res.status(500).json({
      success: false,
      message: 'Internal server error',
    });
  }
});

