// ============================================================
// Local Storage Token Storage Implementation
// ============================================================

const ACCESS_TOKEN_KEY = 'auth_access_token';
const REFRESH_TOKEN_KEY = 'auth_refresh_token';

export class LocalStorageTokenStorage implements TokenStorage {
  getAccessToken(): string | null {
    return localStorage.getItem(ACCESS_TOKEN_KEY);
  }

  getRefreshToken(): string | null {
    return localStorage.getItem(REFRESH_TOKEN_KEY);
  }

  setTokens(accessToken: string, refreshToken: string): void {
    localStorage.setItem(ACCESS_TOKEN_KEY, accessToken);
    localStorage.setItem(REFRESH_TOKEN_KEY, refreshToken);
  }

  clearTokens(): void {
    localStorage.removeItem(ACCESS_TOKEN_KEY);
    localStorage.removeItem(REFRESH_TOKEN_KEY);
  }

  hasTokens(): boolean {
    return !!this.getAccessToken() && !!this.getRefreshToken();
  }
}

// ============================================================
// Default Configuration
// ============================================================

const defaultConfig: ApiClientConfig = {
  baseURL: import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api',
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
  },
  withCredentials: true,
};

const defaultRequestInterceptor: RequestInterceptorConfig = {
  attachToken: true,
  tokenHeaderName: 'Authorization',
  tokenPrefix: 'Bearer',
};

const defaultResponseInterceptor: ResponseInterceptorConfig = {
  autoRefreshToken: true,
  maxRetryAttempts: 1,
};

// ============================================================
// Axios Client Implementation
// ============================================================

class AxiosApiClient implements ApiClient {
  private instance: AxiosInstance;

  constructor(config: ApiClientConfig) {
    this.instance = axios.create({
      baseURL: config.baseURL,
      timeout: config.timeout,
      headers: config.headers,
      withCredentials: config.withCredentials,
    });
  }

  async get<T>(url: string, params?: Record<string, unknown>): Promise<T> {
    const response = await this.instance.get<T>(url, { params });
    return response.data;
  }

  async post<T>(url: string, data?: unknown): Promise<T> {
    const response = await this.instance.post<T>(url, data);
    return response.data;
  }

  async put<T>(url: string, data?: unknown): Promise<T> {
    const response = await this.instance.put<T>(url, data);
    return response.data;
  }

  async patch<T>(url: string, data?: unknown): Promise<T> {
    const response = await this.instance.patch<T>(url, data);
    return response.data;
  }

  async delete<T>(url: string): Promise<T> {
    const response = await this.instance.delete<T>(url);
    return response.data;
  }

  getInstance(): AxiosInstance {
    return this.instance;
  }
}

// ============================================================
// Auth API Implementation
// ============================================================

class AuthApiImpl implements AuthApi {
  constructor(
    private client: AxiosApiClient,
    private tokenStorage: TokenStorage
  ) {}

  async register(data: RegisterRequest): Promise<AuthResponse> {
    return this.client.post<AuthResponse>('/auth/register', data);
  }

  async login(data: LoginRequest): Promise<AuthResponse> {
    const response = await this.client.post<AuthResponse>('/auth/login', data);
    if (response.accessToken && response.refreshToken) {
      this.tokenStorage.setTokens(response.accessToken, response.refreshToken);
    }
    return response;
  }

  async logout(data?: LogoutRequest): Promise<void> {
    try {
      await this.client.post('/auth/logout', data);
    } finally {
      this.tokenStorage.clearTokens();
    }
  }

  async refreshToken(refreshToken: string): Promise<RefreshTokenResponse> {
    const response = await this.client.post<RefreshTokenResponse>('/auth/refresh', {
      refreshToken,
    });
    if (response.accessToken && response.refreshToken) {
      this.tokenStorage.setTokens(response.accessToken, response.refreshToken);
    }
    return response;
  }
}

