// ============================================================
// API Service Factory
// ============================================================

export class ApiServiceImpl implements ApiService {
  public auth: AuthApi;
  public user: UserApi;
  public product: ProductApi;
  public client: ApiClient;

  private axiosClient: AxiosApiClient;
  private tokenStorage: TokenStorage;
  private isRefreshing = false;
  private refreshSubscribers: Array<(token: string) => void> = [];

  constructor(params: ApiServiceInitParams = {}) {
    const config = { ...defaultConfig, ...params.config };
    this.tokenStorage = params.tokenStorage || new LocalStorageTokenStorage();
    const requestInterceptor = {
      ...defaultRequestInterceptor,
      ...params.interceptors?.request,
    };
    const responseInterceptor = {
      ...defaultResponseInterceptor,
      ...params.interceptors?.response,
    };

    this.axiosClient = new AxiosApiClient(config);
    this.client = this.axiosClient;

    // Initialize APIs
    this.auth = new AuthApiImpl(this.axiosClient, this.tokenStorage);
    this.user = new UserApiImpl(this.axiosClient);
    this.product = new ProductApiImpl(this.axiosClient);

    // Setup interceptors
    this.setupRequestInterceptor(requestInterceptor);
    this.setupResponseInterceptor(responseInterceptor);
  }

  private setupRequestInterceptor(config: RequestInterceptorConfig): void {
    const instance = this.axiosClient.getInstance();

    instance.interceptors.request.use(
      (axiosConfig: InternalAxiosRequestConfig) => {
        if (config.attachToken && this.tokenStorage.hasTokens()) {
          const token = this.tokenStorage.getAccessToken();
          if (token && axiosConfig.headers) {
            axiosConfig.headers[config.tokenHeaderName] = `${config.tokenPrefix} ${token}`;
          }
        }
        return axiosConfig;
      },
      (error) => Promise.reject(error)
    );
  }

  private setupResponseInterceptor(config: ResponseInterceptorConfig): void {
    const instance = this.axiosClient.getInstance();

    instance.interceptors.response.use(
      (response) => response,
      async (error: AxiosError) => {
        const originalRequest = error.config as InternalAxiosRequestConfig & {
          _retry?: boolean;
        };

        // Handle 401 Unauthorized
        if (error.response?.status === 401 && !originalRequest._retry) {
          if (config.autoRefreshToken && this.tokenStorage.hasTokens()) {
            if (this.isRefreshing) {
              // Queue the request while refreshing
              return new Promise((resolve) => {
                this.refreshSubscribers.push((token: string) => {
                  if (originalRequest.headers) {
                    originalRequest.headers['Authorization'] = `Bearer ${token}`;
                  }
                  resolve(instance(originalRequest));
                });
              });
            }

            originalRequest._retry = true;
            this.isRefreshing = true;

            try {
              const refreshToken = this.tokenStorage.getRefreshToken();
              if (refreshToken) {
                const response = await this.auth.refreshToken(refreshToken);

                // Notify queued requests
                this.refreshSubscribers.forEach((callback) => callback(response.accessToken));
                this.refreshSubscribers = [];

                // Retry the original request
                if (originalRequest.headers) {
                  originalRequest.headers['Authorization'] = `Bearer ${response.accessToken}`;
                }
                return instance(originalRequest);
              }
            } catch (refreshError) {
              // Notify failed callbacks
              this.refreshSubscribers.forEach((callback) => callback(''));
              this.refreshSubscribers = [];

              // Clear tokens and call failure callback
              this.tokenStorage.clearTokens();
              config.onTokenRefreshFailed?.();

              return Promise.reject(refreshError);
            } finally {
              this.isRefreshing = false;
            }
          }
        }

        return Promise.reject(error);
      }
    );
  }

  // Utility methods
  setTokenStorage(tokenStorage: TokenStorage): void {
    this.tokenStorage = tokenStorage;
    // Re-initialize auth API with new token storage
    this.auth = new AuthApiImpl(this.axiosClient, tokenStorage);
  }

  clearTokens(): void {
    this.tokenStorage.clearTokens();
  }

  hasValidTokens(): boolean {
    return this.tokenStorage.hasTokens();
  }
}

