let apiServiceInstance: ApiService | null = null;

export function getApiService(params?: ApiServiceInitParams): ApiService {
  if (!apiServiceInstance) {
    apiServiceInstance = new ApiServiceImpl(params);
  }
  return apiServiceInstance;
}

export function createApiService(params?: ApiServiceInitParams): ApiService {
  return new ApiServiceImpl(params);
}

export function resetApiService(): void {
