export interface UseApiServiceResult {
  api: ApiService;
  isLoading: boolean;
  error: Error | null;
}

export function createApiServiceWithState(): UseApiServiceResult {
  const api = getApiService();
  return {
    api,
    isLoading: false,
    error: null,
  };
}

