// ============================================================
// Type Definitions
// ============================================================

/** 登录页模式 */
export type LoginPageMode = 'login' | 'register';

/** 登录页表单数据 */
export interface LoginFormData {
  email: string;
  password: string;
}

/** 注册页表单数据 */
export interface RegisterFormData {
  name: string;
  email: string;
  password: string;
  confirmPassword: string;
}

/** 登录页 Props */
export interface LoginPageProps {
  onLoginSuccess?: (user: SafeUser, tokens: TokenPair) => void;
  onRegisterSuccess?: (user: SafeUser, tokens: TokenPair) => void;
  redirectPath?: string;
  onNavigate?: (path: string) => void;
  initialMode?: LoginPageMode;
}

/** 登录页组件状态 */
export interface LoginPageState {
  mode: LoginPageMode;
  submitting: boolean;
  serverError: string | null;
  formErrors: Record<string, string>;
}

/** 登录页表单验证规则 */
export interface ValidationRule {
  field: string;
  required?: boolean;
  minLength?: number;
  maxLength?: number;
  pattern?: RegExp;
  patternMessage?: string;
  customValidator?: (value: string, formData: Record<string, string>) => string | null;
}

/** 登录页表单验证结果 */
export interface ValidationResult {
  valid: boolean;
  errors: Record<string, string>;
}

/** 表单输入事件 */
export type FormInputChangeEvent = React.ChangeEvent<HTMLInputElement>;

/** 表单提交事件 */
export type FormSubmitEvent = React.FormEvent<HTMLFormElement>;

/** 登录页 Toast 通知 */
export interface LoginPageNotification {
  type: 'success' | 'error' | 'info' | 'warning';
  message: string;
  duration?: number;
}

/** 登录页模式切换选项 */
export interface ModeSwitchOption {
  mode: LoginPageMode;
  label: string;
  description: string;
  switchLabel: string;
  switchTo: LoginPageMode;
}

