const LOGIN_VALIDATION_RULES: ValidationRule[] = [
  {
    field: 'email',
    required: true,
    pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
    patternMessage: '请输入有效的邮箱地址'
  },
  {
    field: 'password',
    required: true,
    minLength: 6,
    maxLength: 20,
    patternMessage: '密码长度应为6-20个字符'
  }
];

const REGISTER_VALIDATION_RULES: ValidationRule[] = [
  {
    field: 'name',
    required: true,
    minLength: 2,
    maxLength: 20,
    patternMessage: '用户名长度应为2-20个字符'
  },
  {
    field: 'email',
    required: true,
    pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
    patternMessage: '请输入有效的邮箱地址'
  },
  {
    field: 'password',
    required: true,
    minLength: 6,
    maxLength: 20,
    patternMessage: '密码长度应为6-20个字符'
  },
  {
    field: 'confirmPassword',
    required: true,
    customValidator: (value: string, formData: Record<string, string>) => {
      if (value !== formData.password) {
        return '两次输入的密码不一致';
      }
      return null;
    }
  }
];

// ============================================================
// Validation Functions
// ============================================================

const validateField = (
  value: string,
  rule: ValidationRule,
  formData: Record<string, string>
): string | null => {
  // Required check
  if (rule.required && !value.trim()) {
    return `${rule.field === 'email' ? '邮箱' : rule.field === 'password' ? '密码' : '该字段'}不能为空`;
  }

  // Skip other validations if empty and not required
  if (!value && !rule.required) {
    return null;
  }

  // Min length check
  if (rule.minLength && value.length < rule.minLength) {
    return `${rule.field}长度不能少于${rule.minLength}个字符`;
  }

  // Max length check
  if (rule.maxLength && value.length > rule.maxLength) {
    return `${rule.field}长度不能超过${rule.maxLength}个字符`;
  }

  // Pattern check
  if (rule.pattern && !rule.pattern.test(value)) {
    return rule.patternMessage || '格式不正确';
  }

  // Custom validator
  if (rule.customValidator) {
    return rule.customValidator(value, formData);
  }

  return null;
};

const validateForm = (
  formData: Record<string, string>,
  rules: ValidationRule[]
): ValidationResult => {
  const errors: Record<string, string> = {};
  let valid = true;

  for (const rule of rules) {
    const error = validateField(formData[rule.field] || '', rule, formData);
    if (error) {
      errors[rule.field] = error;
      valid = false;
    }
  }

  return { valid, errors };
};

