const LoginPage: React.FC<LoginPageProps> = ({
  onLoginSuccess,
  onRegisterSuccess,
  redirectPath = '/',
  onNavigate,
  initialMode = 'login'
}) => {
  // State
  const [state, setState] = useState<LoginPageState>({
    mode: initialMode,
    submitting: false,
    serverError: null,
    formErrors: {}
  });

  const [loginForm, setLoginForm] = useState<LoginFormData>({
    email: '',
    password: ''
  });

  const [registerForm, setRegisterForm] = useState<RegisterFormData>({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });

  const [notification, setNotification] = useState<LoginPageNotification | null>(null);

  // Get current rules based on mode
  const validationRules = useMemo(() => {
    return state.mode === 'login' ? LOGIN_VALIDATION_RULES : REGISTER_VALIDATION_RULES;
  }, [state.mode]);

  // Get current form data based on mode
  const currentFormData = useMemo(() => {
    return state.mode === 'login' ? loginForm : registerForm;
  }, [state.mode, loginForm, registerForm]);

  // Form change handlers
  const handleLoginInputChange = useCallback((e: FormInputChangeEvent) => {
    const { name, value } = e.target;
    setLoginForm(prev => ({ ...prev, [name]: value }));
    // Clear field error when user starts typing
    if (state.formErrors[name]) {
      setState(prev => ({
        ...prev,
        formErrors: { ...prev.formErrors, [name]: '' }
      }));
    }
  }, [state.formErrors]);

  const handleRegisterInputChange = useCallback((e: FormInputChangeEvent) => {
    const { name, value } = e.target;
    setRegisterForm(prev => ({ ...prev, [name]: value }));
    // Clear field error when user starts typing
    if (state.formErrors[name]) {
      setState(prev => ({
        ...prev,
        formErrors: { ...prev.formErrors, [name]: '' }
      }));
    }
  }, [state.formErrors]);

  // Combined input change handler
  const handleInputChange = useCallback((e: FormInputChangeEvent) => {
    if (state.mode === 'login') {
      handleLoginInputChange(e);
    } else {
      handleRegisterInputChange(e);
    }
  }, [state.mode, handleLoginInputChange, handleRegisterInputChange]);

  // Mode switch handler
  const handleModeSwitch = useCallback((newMode: LoginPageMode) => {
    setState(prev => ({
      ...prev,
      mode: newMode,
      serverError: null,
      formErrors: {}
    }));
  }, []);

  // Show notification
  const showNotification = useCallback((type: LoginPageNotification['type'], message: string) => {
    setNotification({ type, message });
  }, []);

  // Form validation
  const validateCurrentForm = useCallback((): boolean => {
    const result = validateForm(currentFormData, validationRules);

    if (!result.valid) {
      setState(prev => ({
        ...prev,
        formErrors: result.errors
      }));
      return false;
    }

    return true;
  }, [currentFormData, validationRules]);

  // Form submission
  const handleSubmit = useCallback(async (e: FormSubmitEvent) => {
    e.preventDefault();

    // Clear previous errors
    setState(prev => ({ ...prev, serverError: null }));

    // Validate form
    if (!validateCurrentForm()) {
      return;
    }

    // Set submitting state
    setState(prev => ({ ...prev, submitting: true }));

    try {
      if (state.mode === 'login') {
        const result = await mockLogin(loginForm.email, loginForm.password);
        showNotification('success', '登录成功！');
        onLoginSuccess?.(result.user, result.tokens);

        // Navigate after successful login
        setTimeout(() => {
          onNavigate?.(redirectPath);
        }, 1000);
      } else {
        const result = await mockRegister(
          registerForm.name,
          registerForm.email,
          registerForm.password
        );
        showNotification('success', '注册成功！');
        onRegisterSuccess?.(result.user, result.tokens);

        // Switch to login mode after successful registration
        setTimeout(() => {
          handleModeSwitch('login');
          // Pre-fill email for convenience
          setLoginForm({
            email: registerForm.email,
            password: ''
          });
        }, 1000);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '操作失败，请稍后重试';
      setState(prev => ({ ...prev, serverError: errorMessage }));
      showNotification('error', errorMessage);
    } finally {
      setState(prev => ({ ...prev, submitting: false }));
    }
  }, [
    state.mode,
    loginForm,
    registerForm,
    validateCurrentForm,
    onLoginSuccess,
    onRegisterSuccess,
    redirectPath,
    onNavigate,
    handleModeSwitch,
    showNotification
  ]);

  // Get field value
  const getFieldValue = (field: string): string => {
    return currentFormData[field] as string || '';
  };

  return (
    <div className="login-page">
      {/* Background Pattern */}
      <div className="login-background">
        <div className="bg-circle bg-circle-1" />
        <div className="bg-circle bg-circle-2" />
      </div>

      {/* Main Container */}
      <div className="login-container">
        {/* Left Side - Branding */}
        <div className="login-branding">
          <div className="branding-content">
            <h1 className="branding-title">欢迎回来</h1>
            <p className="branding-subtitle">
              登录您的账户，开始愉快的购物之旅
            </p>
            <div className="branding-features">
              <div className="feature-item">
                <span className="feature-icon">🛍️</span>
                <span>海量商品任您选</span>
              </div>
              <div className="feature-item">
                <span className="feature-icon">⚡</span>
                <span>闪电配送极速达</span>
              </div>
              <div className="feature-item">
                <span className="feature-icon">🔒</span>
                <span>安全支付有保障</span>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side - Form */}
        <div className="login-form-wrapper">
          <div className="login-form-container">
            {/* Logo */}
            <div className="login-logo">
              <span>🔐</span>
            </div>

            {/* Title */}
            <h2 className="login-title">
              {state.mode === 'login' ? '用户登录' : '创建账户'}
            </h2>
            <p className="login-subtitle">
              {state.mode === 'login' 
                ? '请输入您的账号信息登录' 
                : '填写以下信息完成注册'}
            </p>

            {/* Mode Toggle */}
            <ModeToggle mode={state.mode} onToggle={handleModeSwitch} />

            {/* Server Error */}
            {state.serverError && (
              <div className="server-error">
                <span>⚠️</span> {state.serverError}
              </div>
            )}

            {/* Form */}
            <form className="login-form" onSubmit={handleSubmit}>
              {/* Name Field (Register only) */}
              {state.mode === 'register' && (
                <FormInput
                  name="name"
                  label="用户名"
                  value={registerForm.name}
                  onChange={handleRegisterInputChange}
                  error={state.formErrors.name}
                  placeholder="请输入用户名"
                  required
                  disabled={state.submitting}
                  autoComplete="username"
                />
              )}

              {/* Email Field */}
              <FormInput
                name="email"
                label="邮箱"
                type="email"
                value={state.mode === 'login' ? loginForm.email : registerForm.email}
                onChange={handleInputChange}
                error={state.formErrors.email}
                placeholder="请输入邮箱地址"
                required
                disabled={state.submitting}
                autoComplete="email"
              />

              {/* Password Field */}
              <PasswordInput
                name="password"
                label="密码"
                value={state.mode === 'login' ? loginForm.password : registerForm.password}
                onChange={handleInputChange}
                error={state.formErrors.password}
                placeholder="请输入密码"
                required
                disabled={state.submitting}
                autoComplete={state.mode === 'login' ? 'current-password' : 'new-password'}
              />

              {/* Confirm Password Field (Register only) */}
              {state.mode === 'register' && (
                <PasswordInput
                  name="confirmPassword"
                  label="确认密码"
                  value={registerForm.confirmPassword}
                  onChange={handleRegisterInputChange}
                  error={state.formErrors.confirmPassword}
                  placeholder="请再次输入密码"
                  required
                  disabled={state.submitting}
                  autoComplete="new-password"
                />
