                <div className="form-footer">
                  <a href="/forgot-password" className="forgot-link">
                    忘记密码？
                  </a>
                </div>
              )}

              {/* Submit Button */}
              <button
                type="submit"
                className="submit-btn"
                disabled={state.submitting}
              >
                {state.submitting ? (
                  <>
                    <span className="spinner" />
                    处理中...
