              {state.mode === 'login' ? (
                <>
                  还没有账户？
                  <button
                    type="button"
                    className="switch-btn"
                    onClick={() => handleModeSwitch('register')}
                  >
                    立即注册
                  </button>
                </>
              ) : (
                <>
                  已有账户？
                  <button
                    type="button"
                    className="switch-btn"
                    onClick={() => handleModeSwitch('login')}
                  >
                    立即登录
                  </button>
                </>
              )}
            </div>

            {/* Back to Home */}
            <div className="back-home">
              <button
                type="button"
                className="back-btn"
                onClick={() => onNavigate?.('/')}
              >
                ← 返回首页
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Toast Notification */}
