/** API 标准错误响应 */
export interface ApiError {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

/** API 标准成功响应 */
export interface SuccessResponse {
  success: true;
  message: string;
}

/** API 通用响应包装 */
export interface ApiResponse<T = unknown> {
  success: boolean;
  message: string;
  data?: T;
}

/** 分页响应包装 */
export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
  hasNext: boolean;
  hasPrev: boolean;
}

/** 分页查询参数 */
export interface PaginationParams {
  page?: number;
  limit?: number;
  sort?: string;
}

/** JWT Token 载荷 */
export interface JwtPayload {
  userId: string;
  email: string;
  role: UserRole;
  iat: number;
  exp: number;
}

/** Token 对 */
export interface TokenPair {
  accessToken: string;
  refreshToken: string;
}

/** 用户角色枚举 */
export type UserRole = 'user' | 'admin' | 'moderator';

/** MongoDB 文档时间戳 */
export interface Timestamps {
  createdAt: string;
  updatedAt: string;
}

/** MongoDB 文档软删除 */
export interface SoftDeletable {
  isActive: boolean;
  deletedAt?: string | null;
}

