/** API 客户端配置 */
export interface ApiClientConfig {
  baseURL: string;
  timeout: number;
  headers: Record<string, string>;
  withCredentials: boolean;
}

/** API 客户端实例接口 */
export interface ApiClient {
  get<T>(url: string, params?: Record<string, unknown>): Promise<T>;
  post<T>(url: string, data?: unknown): Promise<T>;
  put<T>(url: string, data?: unknown): Promise<T>;
  patch<T>(url: string, data?: unknown): Promise<T>;
  delete<T>(url: string): Promise<T>;
}

/** Token 存储接口 */
export interface TokenStorage {
  getAccessToken(): string | null;
  getRefreshToken(): string | null;
  setTokens(accessToken: string, refreshToken: string): void;
  clearTokens(): void;
  hasTokens(): boolean;
}

/** Auth API 接口 */
export interface AuthApi {
  register(data: RegisterRequest): Promise<AuthResponse>;
  login(data: LoginRequest): Promise<AuthResponse>;
  logout(data?: LogoutRequest): Promise<void>;
  refreshToken(refreshToken: string): Promise<RefreshTokenResponse>;
}

/** User API 接口 */
export interface UserApi {
  getMe(): Promise<SafeUser>;
  getUserById(id: string): Promise<UserPublic>;
  updateMe(data: UpdateUserRequest): Promise<SafeUser>;
  changePassword(data: ChangePasswordRequest): Promise<PasswordChangeResponse>;
}

/** Product API 接口 */
export interface ProductApi {
  getProducts(params?: ProductQueryParams): Promise<PaginatedResponse<Product>>;
  getProductById(id: string): Promise<Product>;
  createProduct(data: CreateProductRequest): Promise<Product>;
  updateProduct(id: string, data: UpdateProductRequest): Promise<Product>;
  deleteProduct(id: string): Promise<ProductDeleteResponse>;
}

/** 组合 API 服务 */
export interface ApiService {
  auth: AuthApi;
  user: UserApi;
  product: ProductApi;
  client: ApiClient;
}

/** API 请求拦截器配置 */
export interface RequestInterceptorConfig {
  attachToken: boolean;
  tokenHeaderName: string;
  tokenPrefix: string;
}

/** API 响应拦截器配置 */
export interface ResponseInterceptorConfig {
  autoRefreshToken: boolean;
  maxRetryAttempts: number;
  onTokenRefreshFailed?: () => void;
}

/** API 拦截器 */
export interface ApiInterceptors {
  request: RequestInterceptorConfig;
  response: ResponseInterceptorConfig;
}

/** API 服务初始化参数 */
export interface ApiServiceInitParams {
  config?: Partial<ApiClientConfig>;
  tokenStorage?: TokenStorage;
  interceptors?: Partial<ApiInterceptors>;
}

